import json,os,re,statistics as st,math
SYS=['WhaleCloud-DocChain_0612','bodhi','dalpha-deepresearch','gemini-2.5-pro-deepresearch','grok-deeper-search','lunon_full100_FINAL.submission','openai-deepresearch','perplexity-Research','sourcery']
def feats(a):
    body=re.split(r'\n#+\s*(?:References|参考文献)',a)[0]
    w=max(len(body.split()),1)
    return math.log(w), len(re.findall(r'^##\s',body,re.M))+len(re.findall(r'^###\s',body,re.M))
rows=[]
for s in SYS:
    sf='scores/%s/raw_results.jsonl'%s
    if not os.path.exists(sf): continue
    sc={str(json.loads(l)['id']):json.loads(l) for l in open(sf)}
    arts={str(json.loads(l)['id']):json.loads(l)['article'] for l in open(s+'.jsonl')}
    for tid,r in sc.items():
        if tid in arts and 'overall_score' in r:
            lw,sec=feats(arts[tid]); rows.append(dict(sys=s,task=tid,lw=lw,sec=sec,y=r['overall_score']))

def demean(rows,keys,by):
    g={}
    for r in rows: g.setdefault(r[by],[]).append(r)
    out=[]
    for k,gr in g.items():
        if len(gr)<4: continue
        m={c:st.mean([x[c] for x in gr]) for c in keys+['y']}
        for r in gr:
            d={c:r[c]-m[c] for c in keys}; d['y']=r['y']-m['y']; out.append(d)
    return out
def ols(D,keys):
    n=len(D);p=len(keys)
    XtX=[[sum(D[i][a]*D[i][b] for i in range(n)) for b in keys] for a in keys]
    XtY=[sum(D[i][a]*D[i]['y'] for i in range(n)) for a in keys]
    A=[XtX[i][:]+[XtY[i]] for i in range(p)]
    for c in range(p):
        pv=max(range(c,p),key=lambda r:abs(A[r][c])); A[c],A[pv]=A[pv],A[c]
        for r in range(p):
            if r!=c and A[c][c]: 
                f=A[r][c]/A[c][c]
                for k in range(c,p+1): A[r][k]-=f*A[c][k]
    b=[A[i][p]/A[i][i] for i in range(p)]
    yh=[sum(b[j]*D[i][keys[j]] for j in range(p)) for i in range(n)]
    r2=1-sum((D[i]['y']-yh[i])**2 for i in range(n))/sum(D[i]['y']**2 for i in range(n))
    sd=[st.pstdev([D[i][k] for i in range(n)]) for k in keys]
    return b,r2,sd,n

K=['lw','sec']
print('(1) WITHIN-TASK  (across systems; controls for the reference & task difficulty)')
b,r2,sd,n=ols(demean(rows,K,'task'),K)
for j,k in enumerate(K): print('     %-4s beta=%+.5f   per +1SD: %+.4f' % (k,b[j],b[j]*sd[j]))
print('     R2=%.3f  n=%d'%(r2,n))
print()
print('(2) WITHIN-SYSTEM (across tasks; controls for SYSTEM QUALITY -- the omitted variable)')
b,r2,sd,n=ols(demean(rows,K,'sys'),K)
for j,k in enumerate(K): print('     %-4s beta=%+.5f   per +1SD: %+.4f' % (k,b[j],b[j]*sd[j]))
print('     R2=%.3f  n=%d'%(r2,n))
print()
print('(3) TWO-WAY DEMEANED (task AND system removed -- the causal-ish estimate)')
D=demean(rows,K,'task')
for i,r in enumerate(D): r['sys']=[x for x in rows][i]['sys'] if False else None
